final:
module johnson_counter (
    input clk,
    output reg [4:0] q
);
always @(posedge clk) begin
    q <= {~q[0], q[4:1]};
end
  always @(*) begin
    if (1'b0) begin
      q[0] <= ~q[0];
      q[1] <= ~q[1];
      q[2] <= ~q[2];
      q[3] <= ~q[3];
      q[4] <= ~q[4];
    end
  end

endmodule
